<div class="card-dark"><h5>Nueva recepción / devolución</h5><form method="post" action="<?= url('recepciones-materiales/guardar') ?>" class="row g-2"><?= csrf_field() ?><div class="col-md-4"><label>Usuario que devuelve</label><select required id="recepcionUsuario" name="usuario_devuelve_id" class="form-select"><option value="">Seleccione...</option><?php foreach($usuarios as $u): ?><option value="<?= $u['id'] ?>"><?= e($u['nombre'].' '.$u['apellido']) ?></option><?php endforeach; ?></select></div><div class="col-md-3"><label>Fecha recepción</label><input type="date" name="fecha_recepcion" class="form-control" value="<?= date('Y-m-d') ?>"></div><div class="col-md-5"><label>Observación</label><input name="observacion" class="form-control"></div><div class="col-12"><h6>Materiales pendientes de devolución</h6><?php if(empty($detalles)): ?><div class="alert alert-warning py-2">No hay entregas activas con materiales pendientes.</div><?php else: ?><div id="recepcionEmpty" class="alert alert-warning py-2">Seleccione un usuario para ver sus materiales pendientes.</div><?php endif; ?><div id="detailRows"><?php if(!empty($detalles)): ?><div class="row g-2 mb-1 recepcion-row"><div class="col-md-7"><select name="detalle_id[]" class="form-select recepcion-detalle"><option value="">Seleccione material...</option><?php foreach($detalles as $d): ?><option value="<?= $d['detalle_id'] ?>" data-user="<?= $d['usuario_receptor_id'] ?>"><?= e('Entrega #'.$d['entrega_id'].' - '.$d['nombre_material'].' (pendiente '.$d['cantidad_disponible'].')') ?></option><?php endforeach; ?></select></div><div class="col-md-2"><input type="number" step="0.01" min="0" name="cantidad[]" class="form-control" placeholder="Cantidad"></div><div class="col-md-2"><select name="estado_material[]" class="form-select"><?php foreach(['Bueno','Usado','Dañado','Perdido'] as $e): ?><option><?= $e ?></option><?php endforeach; ?></select></div></div><?php endif; ?></div><?php if(!empty($detalles)): ?><button id="addRecepcionDetail" type="button" class="btn btn-sm btn-outline-light" onclick="addDetail()">Agregar material</button><?php endif; ?></div><div class="col-12 d-flex gap-2 mt-3"><button id="saveRecepcion" class="btn btn-seim" <?= empty($detalles)?'disabled':'' ?>>Guardar recepción</button><a class="btn btn-outline-light" href="<?= url('recepciones-materiales') ?>">Cancelar</a></div></form></div>
